charts.get = function(chartHolder, data) {
    return new Chart(chartHolder, data);
};

export function Chart(container, data) {
    let self = this;
    this.container = container;
    this.userdata = data;
    this.dataObject = null;
    this.dataset = null;
    this.svg = null;
    this.seriesColor = [];
    this.axes = {
        x: {
            levels: [],
            branches: [],
            clusters: [],
            leaves: []
        },
        y: {
            groups: [],
            branches: [],
            clusters: [],
            leaves: []
        }
    };
    // this.renderer = [];
    this.ismultiy = null;
    this.plotarea_approx = null;
    this.nochartdata = false;
    this.chartRendered = false;
    this.plot = {};
    this.events = {};

    this.viewPortExtent = null;
    this.isMiniature = this.isMiniature || getPropVal(data, 'chart.plot.miniature') ;
    this.customVisual = data._viewParser && data.renderOldConfig == false;
    // this.legend = {
    //     component: null
    // };

    // extend VizLayout
    if (this.isMiniature) {
        canvas_plot_renderer.sparkline(this);
    } else {
        VizLayout.call(this, container, data);
        this.initialize();
    }
    
}

